import React, { useState } from "react";
import App from "../App";
const THEMES = {
blue :{
  text:"px-3 py-2 rounded bg-black/40 border border-gray-700 text-blue",
  rangeInput:"w-14 h-2 cursor-pointer accent-blue-500 ",
  send : "bg-blue-600 px-4 py-2 rounded hover:bg-blue-700 disabled:opacity-50" 
},

orange: {
  text:"px-3 py-2 rounded bg-black/40 border border-gray-700 text-orange",
  rangeInput:"w-14 h-2 cursor-pointer accent-orange-500",
  send : "bg-orange-600 px-4 py-2 rounded hover:bg-orange-700 disabled:opacity-50"
}
};
export default function ClueInput({ team = "blue",onSend, disabled }) {
  const t = THEMES[team] ?? THEMES.blue;
  const [clueWord, setClueWord] = useState("");
  const [clueCount, setClueCount] = useState(1);

  const handleSend = () => {
    if (!clueWord.trim() || disabled) return;
    onSend({ clue: clueWord, count: clueCount });
    setClueWord("");
    setClueCount(1);
  };
  const ThemeBlue= "w-14 h-2 cursor-pointer accent-blue-500";
const ThemeOrange ="w-14 h-2 cursor-pointer accent-orange-500";
  return (
    <div className={disabled ? "":"flex items-center gap-3 bg-gray-900 p-3 rounded-xl shadow-lg" }>
      <input
        type="text"
        placeholder="Enter clue..."
        value={clueWord}
        onChange={(e) => setClueWord(e.target.value)}
        className={disabled ? "sm:hidden" : t.text}
      />

      <input
        type="range"
        min={1}
        max={9}
        value={clueCount}
        onChange={(e) => setClueCount(Number(e.target.value))}
className={disabled ? "sm:hidden" :t.rangeInput}     />
       <output for="volume" id="volumeOutput" >{clueCount}</output>


      <button
        onClick={handleSend}
        disabled={disabled}
        className={disabled ? "sm:hidden" :t.send}
      >
        Send
      </button>
    </div>
  );
}
